private def powermod(a: Long, b: Long, mod: Long): Long = {
    var base = a % mod
    if (base < 0) base += mod
    var result = 1L
    var exp = b
    while (exp > 0) {
        if ((exp & 1) != 0) {
            result = (result * base) % mod
        }
        base = (base * base) % mod
        exp = exp >> 1
    }
    result
}

def solve(nums: Array[Long], queries: Array[Array[Long]]): Long = {
    val MOD = 1000000007L
    val n = nums.length
    val MAX_V = 100000
    val invTable = new Array[Long](MAX_V + 1)
    for (v0 <- 1 to MAX_V) {
        invTable(v0) = powermod(v0, MOD - 2, MOD)
    }

    val K0 = math.sqrt(n).toInt
    val fact = Array.fill(n)(1L)

    val smallQueriesBuffer = Array.fill(K0 + 1)(scala.collection.mutable.ArrayBuffer[Array[Long]]())
    val largeBuffer = scala.collection.mutable.ArrayBuffer[Array[Long]()
    for (qry <- queries) {
        val k = qry(2)
        if (k >= 1 && k <= K0) {
            smallQueriesBuffer(k.toInt) += qry
        } else {
            largeBuffer += qry
        }
    }
    val largeQueries = largeBuffer.toArray

    for (k_val <- 1 to K0) {
        val qlist = smallQueriesBuffer(k_val).toList
        if (qlist.nonEmpty) {
            val queriesByResidue = Array.fill(k_val)(scala.collection.mutable.ArrayBuffer[Array[Long]]())
            for (qry <- qlist) {
                val residue = (qry(0) % k_val).toInt
                queriesByResidue(residue) += qry
            }

            for (r0 <- 0 until k_val) {
                val qlist_res = queriesByResidue(r0).toList
                if (qlist_res.nonEmpty) {
                    val size = if (r0 > n - 1) 0 else ((n - 1 - r0) / k_val) + 1
                    if (size > 0) {
                        val temp = Array.fill(size + 1)(1L)
                        for (qry <- qlist_res) {
                            val l = qry(0)
                            val r = qry(1)
                            val v = qry(3)

                            var t_low: Long = 0
                            if (r0 < l) {
                                t_low = (l - r0 + k_val - 1) / k_val
                            }
                            if (t_low < 0) t_low = 0
                            if (t_low < size) {
                                var t_high = (r - r0) / k_val
                                if (t_high >= size) t_high = size - 1
                                if (t_high >= t_low) {
                                    val start = t_low.toInt
                                    val end = t_high.toInt
                                    temp(start) = (temp(start) * v) % MOD
                                    if (end + 1 < size) {
                                        temp(end + 1) = (temp(end + 1) * invTable(v.toInt)) % MOD
                                    }
                                }
                            }
                        }

                        var factor = 1L
                        for (t_index <- 0 until size) {
                            factor = (factor * temp(t_index)) % MOD
                            val j = r0 + t_index * k_val
                            if (j < n) {
                                fact(j.toInt) = (fact(j.toInt) * factor) % MOD
                            }
                        }
                    }
                }
            }
        }
    }

    for (qry <- largeQueries) {
        val l = qry(0)
        val r = qry(1)
        val k = qry(2)
        val v = qry(3)
        var j = l
        while (j <= r) {
            val idx = j.toInt
            fact(idx) = (fact(idx) * v) % MOD
            j += k
        }
    }

    var ans = 0L
    for (i <- 0 until n) {
        nums(i) = (nums(i) * fact(i)) % MOD
        ans = ans ^ nums(i)
    }
    ans
}
```

### Explanation
1. **Initialization**:
   - **Precompute Modular Inverses**: For values `1` to `100,000`, compute their modular inverses under `10^9 + 7` using Fermat's Little Theorem.
   - **Split Queries**: Separate queries into those with small (`k ≤ √n`) and large (`k > √n`) step sizes.

2. **Processing Small Step Queries**:
   - **Group by Residue**: For each small `k`, group queries by `l mod k`.
   - **Difference Array Technique**: For each residue group, use a difference array to mark the start and end of multiplicative update ranges. This allows efficient prefix product computation to apply all updates in linear time.

3. **Processing Large Step Queries**:
   - **Direct Update**: For each large step query, directly iterate and update the indices in the arithmetic progression, as each such query affects at most `O(√n)` indices.

4. **Final Update and XOR Calculation**:
   - **Apply Factors**: Multiply each element in the original array by its accumulated factor (from both small and large queries) modulo `10^9 + 7`.
   - **Compute XOR**: Calculate the bitwise XOR of all updated array elements to produce the final result.

This approach efficiently handles the constraints by leveraging mathematical insights and optimized update techniques, ensuring optimal performance even for large inputs.
